#include <stdio.h>
#include <stdlib.h>

int N;
int a[8];
int used[8];
int cur[8];
int **perms; // array of pointers to int arrays
int permCount = 0;

void backtrack(int pos) {
    if (pos == N) {
        int *p = (int *)malloc(N * sizeof(int));
        for (int i = 0; i < N; ++i) p[i] = cur[i];
        perms[permCount++] = p;
        return;
    }
    for (int i = 0; i < N; ++i) {
        if (used[i]) continue;
        if (i > 0 && a[i] == a[i-1] && !used[i-1]) continue; // skip duplicates
        used[i] = 1;
        cur[pos] = a[i];
        backtrack(pos + 1);
        used[i] = 0;
    }
}

int cmpInt(const void *p, const void *q) {
    int x = *(const int *)p;
    int y = *(const int *)q;
    return (x > y) - (x < y);
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        scanf("%d", &N);
        for (int i = 0; i < N; ++i) scanf("%d", &a[i]);
        qsort(a, N, sizeof(int), cmpInt);
        for (int i = 0; i < N; ++i) used[i] = 0;
        // maximum possible permutations for N<=8 is 40320
        perms = (int **)malloc(40320 * sizeof(int *));
        permCount = 0;
        backtrack(0);
        printf("%d\n", permCount);
        for (int i = 0; i < permCount; ++i) {
            for (int j = 0; j < N; ++j) {
                if (j) printf(" ");
                printf("%d", perms[i][j]);
            }
            printf("\n");
            free(perms[i]);
        }
        free(perms);
    }
    return 0;
}

