#include <bits/stdc++.h>
using namespace std;

void backtrack(const vector<int>& a, vector<int>& cur, vector<bool>& used, vector<vector<int>>& res) {
    int n = a.size();
    if ((int)cur.size() == n) {
        res.push_back(cur);
        return;
    }
    for (int i = 0; i < n; ++i) {
        if (used[i]) continue;
        if (i > 0 && a[i] == a[i-1] && !used[i-1]) continue; // avoid duplicates
        used[i] = true;
        cur.push_back(a[i]);
        backtrack(a, cur, used, res);
        cur.pop_back();
        used[i] = false;
    }
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while (T--) {
        int N; cin>>N;
        vector<int> a(N);
        for (int &x: a) cin>>x;
        sort(a.begin(), a.end());
        vector<vector<int>> perms;
        vector<int> cur;
        vector<bool> used(N,false);
        backtrack(a, cur, used, perms);
        cout << perms.size() << '\n';
        for (auto &p: perms) {
            for (int i = 0; i < N; ++i) {
                if (i) cout << ' ';
                cout << p[i];
            }
            cout << '\n';
        }
    }
    return 0;
}

