import java.io.*;
import java.util.*;

public class Main {
    static void backtrack(int[] a, boolean[] used, List<Integer> cur, List<int[]> res) {
        int n = a.length;
        if (cur.size() == n) {
            int[] perm = new int[n];
            for (int i = 0; i < n; i++) perm[i] = cur.get(i);
            res.add(perm);
            return;
        }
        for (int i = 0; i < n; i++) {
            if (used[i]) continue;
            if (i > 0 && a[i] == a[i-1] && !used[i-1]) continue; // skip duplicate
            used[i] = true;
            cur.add(a[i]);
            backtrack(a, used, cur, res);
            cur.remove(cur.size() - 1);
            used[i] = false;
        }
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st;
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder out = new StringBuilder();
        while (T-- > 0) {
            int N = Integer.parseInt(br.readLine().trim());
            st = new StringTokenizer(br.readLine());
            int[] a = new int[N];
            for (int i = 0; i < N; i++) a[i] = Integer.parseInt(st.nextToken());
            Arrays.sort(a);
            List<int[]> perms = new ArrayList<>();
            backtrack(a, new boolean[N], new ArrayList<>(), perms);
            out.append(perms.size()).append('\n');
            for (int[] p : perms) {
                for (int i = 0; i < N; i++) {
                    if (i > 0) out.append(' ');
                    out.append(p[i]);
                }
                out.append('\n');
            }
        }
        System.out.print(out.toString());
    }
}

