#!/usr/bin/env python3
import sys

def backtrack(a, used, cur, res):
    if len(cur) == len(a):
        res.append(cur.copy())
        return
    for i in range(len(a)):
        if used[i]:
            continue
        if i > 0 and a[i] == a[i-1] and not used[i-1]:
            continue
        used[i] = True
        cur.append(a[i])
        backtrack(a, used, cur, res)
        cur.pop()
        used[i] = False

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        a = [int(next(it)) for _ in range(N)]
        a.sort()
        res = []
        backtrack(a, [False]*N, [], res)
        out_lines.append(str(len(res)))
        for perm in res:
            out_lines.append(' '.join(map(str, perm)))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

