function backtrack(a, used, cur, res) {
  if (cur.length === a.length) {
    res.push(cur.slice());
    return;
  }
  for (let i = 0; i < a.length; i++) {
    if (used[i]) continue;
    if (i > 0 && a[i] === a[i-1] && !used[i-1]) continue; // skip duplicate
    used[i] = true;
    cur.push(a[i]);
    backtrack(a, used, cur, res);
    cur.pop();
    used[i] = false;
  }
}
for (let t = 0; t < T; t++) {
  const N = Number(input[idx++]);
  const a = [];
  for (let i = 0; i < N; i++) a.push(Number(input[idx++]));
  a.sort((x, y) => x - y);
  const res = [];
  backtrack(a, new Array(N).fill(false), [], res);
  output.push(String(res.length));
  for (const p of res) {
    output.push(p.join(' '));
